#include "reverse_linked_list.h"
#include <stdlib.h>

typedef struct Node {
    int value;
    struct Node* next;
} Node;

static Node* build_list(int arr[], int n) {
    if (n == 0) {
        return NULL;
    }
    Node* head = (Node*)malloc(sizeof(Node));
    head->value = arr[0];
    head->next = NULL;
    Node* current = head;
    for (int i = 1; i < n; i++) {
        current->next = (Node*)malloc(sizeof(Node));
        current = current->next;
        current->value = arr[i];
        current->next = NULL;
    }
    return head;
}

static void free_list(Node* head) {
    while (head != NULL) {
        Node* next = head->next;
        free(head);
        head = next;
    }
}

void reverse_linked_list(int arr[], int n, int result[], int* result_size) {
    Node* head = build_list(arr, n);

    Node* prev = NULL;
    Node* current = head;
    while (current != NULL) {
        Node* next = current->next;
        current->next = prev;
        prev = current;
        current = next;
    }

    *result_size = 0;
    Node* cur = prev;
    while (cur != NULL) {
        result[*result_size] = cur->value;
        (*result_size)++;
        cur = cur->next;
    }

    free_list(prev);
}

#include <vector>

struct Node {
    int value;
    Node* next;
    Node(int v) : value(v), next(nullptr) {}
};

static Node* buildList(const std::vector<int>& arr) {
    if (arr.empty()) {
        return nullptr;
    }
    Node* head = new Node(arr[0]);
    Node* current = head;
    for (size_t i = 1; i < arr.size(); i++) {
        current->next = new Node(arr[i]);
        current = current->next;
    }
    return head;
}

static std::vector<int> toArray(Node* head) {
    std::vector<int> result;
    Node* current = head;
    while (current != nullptr) {
        result.push_back(current->value);
        current = current->next;
    }
    return result;
}

static void freeList(Node* head) {
    while (head != nullptr) {
        Node* next = head->next;
        delete head;
        head = next;
    }
}

std::vector<int> reverseLinkedList(std::vector<int> arr) {
    Node* head = buildList(arr);

    Node* prev = nullptr;
    Node* current = head;
    while (current != nullptr) {
        Node* next = current->next;
        current->next = prev;
        prev = current;
        current = next;
    }

    std::vector<int> result = toArray(prev);
    freeList(prev);
    return result;
}

using System.Collections.Generic;

public class ReverseLinkedList
{
    private class ListNode
    {
        public int Value;
        public ListNode Next;

        public ListNode(int value)
        {
            Value = value;
        }
    }

    private static ListNode BuildList(int[] arr)
    {
        if (arr.Length == 0) return null;
        ListNode head = new ListNode(arr[0]);
        ListNode current = head;
        for (int i = 1; i < arr.Length; i++)
        {
            current.Next = new ListNode(arr[i]);
            current = current.Next;
        }
        return head;
    }

    private static int[] ToArray(ListNode head)
    {
        List<int> result = new List<int>();
        ListNode current = head;
        while (current != null)
        {
            result.Add(current.Value);
            current = current.Next;
        }
        return result.ToArray();
    }

    public static int[] Reverse(int[] arr)
    {
        ListNode head = BuildList(arr);

        ListNode prev = null;
        ListNode current = head;
        while (current != null)
        {
            ListNode next = current.Next;
            current.Next = prev;
            prev = current;
            current = next;
        }

        return ToArray(prev);
    }
}

