func buildList(arr []int) *node {
	if len(arr) == 0 {
		return nil
	}
	head := &node{value: arr[0]}
	current := head
	for i := 1; i < len(arr); i++ {
		current.next = &node{value: arr[i]}
		current = current.next
	}
	return head
}

func toArray(head *node) []int {
	result := []int{}
	current := head
	for current != nil {
		result = append(result, current.value)
		current = current.next
	}
	return result
}

// ReverseLinkedList builds a linked list from an array, reverses it, and returns the result as an array.
func ReverseLinkedList(arr []int) []int {
	head := buildList(arr)

	var prev *node
	current := head
	for current != nil {
		next := current.next
		current.next = prev
		prev = current
		current = next
	}

	return toArray(prev)
}

public class ReverseLinkedList {

    private static class Node {
        int value;
        Node next;

        Node(int value) {
            this.value = value;
        }
    }

    private static Node buildList(int[] arr) {
        if (arr.length == 0) {
            return null;
        }
        Node head = new Node(arr[0]);
        Node current = head;
        for (int i = 1; i < arr.length; i++) {
            current.next = new Node(arr[i]);
            current = current.next;
        }
        return head;
    }

    private static int[] toArray(Node head) {
        int count = 0;
        Node current = head;
        while (current != null) {
            count++;
            current = current.next;
        }
        int[] result = new int[count];
        current = head;
        for (int i = 0; i < count; i++) {
            result[i] = current.value;
            current = current.next;
        }
        return result;
    }

    public static int[] reverseLinkedList(int[] arr) {
        Node head = buildList(arr);

        Node prev = null;
        Node current = head;
        while (current != null) {
            Node next = current.next;
            current.next = prev;
            prev = current;
            current = next;
        }

        return toArray(prev);
    }
}

private class ListNode(val value: Int, var next: ListNode? = null)

private fun buildList(arr: IntArray): ListNode? {
    if (arr.isEmpty()) return null
    val head = ListNode(arr[0])
    var current = head
    for (i in 1 until arr.size) {
        current.next = ListNode(arr[i])
        current = current.next!!
    }
    return head
}

private fun toArray(head: ListNode?): IntArray {
    val result = mutableListOf<Int>()
    var current = head
    while (current != null) {
        result.add(current.value)
        current = current.next
    }
    return result.toIntArray()
}

fun reverseLinkedList(arr: IntArray): IntArray {
    var head = buildList(arr)

    var prev: ListNode? = null
    var current = head
    while (current != null) {
        val next = current.next
        current.next = prev
        prev = current
        current = next
    }

    return toArray(prev)
}

